    # When the activity was last edited
    edited_at: Optional[datetime] = dc_field(default=None, metadata=dc_config(field_name="edited_at", encoder=encode_datetime, decoder=datetime_from_unix_ns, mm_field=fields.DateTime(format="iso")))
    # When the activity will expire
    expires_at: Optional[datetime] = dc_field(default=None, metadata=dc_config(field_name="expires_at", encoder=encode_datetime, decoder=datetime_from_unix_ns, mm_field=fields.DateTime(format="iso")))
    # Total count of reactions from friends on this activity
    friend_reaction_count: Optional[int] = dc_field(default=None, metadata=dc_config(field_name="friend_reaction_count"))
