    is_watched: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="is_watched"))
    moderation_action: Optional[str] = dc_field(default=None, metadata=dc_config(field_name="moderation_action"))
    # Which activity selector provided this activity (e.g., 'following', 'popular', 'interest'). Only set when using multiple activity selectors with ranking.
    selector_source: Optional[str] = dc_field(default=None, metadata=dc_config(field_name="selector_source"))
    # Text content of the activity
    text: Optional[str] = dc_field(default=None, metadata=dc_config(field_name="text"))
    # If visibility is 'tag', this is the tag name
    visibility_tag: Optional[str] = dc_field(default=None, metadata=dc_config(field_name="visibility_tag"))
    # Reactions from users the current user follows or has mutual follows with
