    current_feed: 'Optional[FeedResponse]' = dc_field(default=None, metadata=dc_config(field_name="current_feed"))
    location: 'Optional[ActivityLocation]' = dc_field(default=None, metadata=dc_config(field_name="location"))
    metrics: 'Optional[Dict[str, int]]' = dc_field(default=None, metadata=dc_config(field_name="metrics"))
    moderation: 'Optional[ModerationV2Response]' = dc_field(default=None, metadata=dc_config(field_name="moderation"))
    notification_context: 'Optional[NotificationContext]' = dc_field(default=None, metadata=dc_config(field_name="notification_context"))
    parent: 'Optional[ActivityResponse]' = dc_field(default=None, metadata=dc_config(field_name="parent"))
    poll: 'Optional[PollResponseData]' = dc_field(default=None, metadata=dc_config(field_name="poll"))
    # Variable values used at ranking time. Only included when include_score_vars is enabled in enrichment options.
    score_vars: Optional[Dict[str, object]] = dc_field(default=None, metadata=dc_config(field_name="score_vars"))

