@dataclass
class EnrichmentOptions(DataClassJsonMixin):
    # Default: false. When true, includes fetching and enriching own_followings (follows where activity author's feeds follow current user's feeds).
    enrich_own_followings: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="enrich_own_followings"))
    # Default: false. When true, includes score_vars in activity responses containing variable values used at ranking time.
    include_score_vars: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="include_score_vars"))
    # Default: false. When true, skips all activity enrichments.
    skip_activity: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity"))
    # Default: false. When true, skips enriching collections on activities.
    skip_activity_collections: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_collections"))
    # Default: false. When true, skips enriching comments on activities.
    skip_activity_comments: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_comments"))
    # Default: false. When true, skips enriching current_feed on activities. Note: CurrentFeed is still computed for permission checks, but enrichment is skipped.
    skip_activity_current_feed: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_current_feed"))
    # Default: false. When true, skips enriching mentioned users on activities.
    skip_activity_mentioned_users: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_mentioned_users"))
    # Default: false. When true, skips enriching own bookmarks on activities.
    skip_activity_own_bookmarks: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_own_bookmarks"))
    # Default: false. When true, skips enriching parent activities.
    skip_activity_parents: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_parents"))
    # Default: false. When true, skips enriching poll data on activities.
    skip_activity_poll: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_poll"))
    # Default: false. When true, skips fetching and enriching latest and own reactions on activities. Note: If reactions are already denormalized in the database, they will still be included.
    skip_activity_reactions: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_reactions"))
    # Default: false. When true, skips refreshing image URLs on activities.
    skip_activity_refresh_image_urls: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_activity_refresh_image_urls"))
    # Default: false. When true, skips all enrichments.
    skip_all: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_all"))
    # Default: false. When true, skips enriching user data on feed members.
    skip_feed_member_user: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_feed_member_user"))
    # Default: false. When true, skips fetching and enriching followers. Note: If followers_pagination is explicitly provided, followers will be fetched regardless of this setting.
    skip_followers: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_followers"))
    # Default: false. When true, skips fetching and enriching following. Note: If following_pagination is explicitly provided, following will be fetched regardless of this setting.
    skip_following: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_following"))
    # Default: false. When true, skips computing and including capabilities for feeds.
    skip_own_capabilities: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_own_capabilities"))
    # Default: false. When true, skips fetching and enriching own_follows (follows where user's feeds follow target feeds).
    skip_own_follows: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_own_follows"))
    # Default: false. When true, skips enriching pinned activities.
    skip_pins: Optional[bool] = dc_field(default=None, metadata=dc_config(field_name="skip_pins"))

